// @ts-check
import { defineConfig, devices } from '@playwright/test';

/**
 * @see https://playwright.dev/docs/test-configuration
 */
export default defineConfig({
    testDir: './tests',
    /* Run tests in files in parallel */
    fullyParallel: true,
    /* Fail the build on CI if you accidentally left test.only in the source code. */
    forbidOnly: !!process.env.CI,
    /* Retry on CI only */
    retries: process.env.CI ? 2 : 0,
    /* Opt out of parallel tests on CI. */
    workers: process.env.CI ? 1 : undefined,
    /* Reporter to use. See https://playwright.dev/docs/test-reporters */
    reporter: 'html',
    /* Shared settings for all the projects below. See https://playwright.dev/docs/api/class-testoptions. */
    use: {
        /* Base URL to use in actions like `await page.goto('/')`. */
        baseURL: 'http://localhost:5174',

        /* Collect trace when retrying the failed test. See https://playwright.dev/docs/trace-viewer */
        trace: 'on-first-retry',
    },

    /* Configure projects for major browsers */
    projects: [
        {
            name: 'chromium',
            use: { ...devices['Desktop Chrome'] },
        },
        // {
        //   name: 'firefox',
        //   use: { ...devices['Desktop Firefox'] },
        // },
        // {
        //   name: 'webkit',
        //   use: { ...devices['Desktop Safari'] },
        // },
    ],

    /* Run your local dev server before starting the tests */
    // webServer: {
    //   command: 'npm run dev',
    //   url: 'http://127.0.0.1:5173',
    //   reuseExistingServer: !process.env.CI,
    // },
});

import React, { useState } from 'react';
import { X, User, Mail, Lock, Briefcase, GraduationCap, Building, MapPin, Linkedin } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import api from '../services/api';

const AddUserModal = ({ isOpen, onClose, onUserAdded }) => {
    const [role, setRole] = useState('student'); // student, alumni, admin
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        batch: '',
        department: '',
        company: '',
        jobTitle: '',
        location: '',
        linkedin: '',
        skills: ''
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const payload = {
                ...formData,
                role,
                skills: formData.skills ? formData.skills.split(',').map(s => s.trim()) : []
            };
            await api.post('/users', payload);
            onUserAdded();
            onClose();
            // Reset form
            setFormData({
                name: '', email: '', password: '', batch: '', department: '', company: '', jobTitle: '', location: '', linkedin: '', skills: ''
            });
            setRole('student');
        } catch (err) {
            console.error("Failed to add user", err);
            setError(err.response?.data?.message || 'Failed to create user');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                />

                <motion.div
                    initial={{ opacity: 0, scale: 0.95, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95, y: 20 }}
                    className="relative w-full max-w-lg bg-white rounded-2xl shadow-xl overflow-hidden"
                >
                    {/* Header */}
                    <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                        <h2 className="text-xl font-bold text-slate-900">Add New User</h2>
                        <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-slate-600">
                            <X size={20} />
                        </button>
                    </div>

                    <form onSubmit={handleSubmit} className="p-8 space-y-6">
                        {/* Role Selector */}
                        <div className="grid grid-cols-3 gap-2 p-1 bg-slate-100 rounded-xl">
                            {['student', 'alumni', 'admin'].map((r) => (
                                <button
                                    key={r}
                                    type="button"
                                    onClick={() => setRole(r)}
                                    className={`py-2 px-4 rounded-lg text-sm font-semibold capitalize transition-all ${role === r ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                                        }`}
                                >
                                    {r}
                                </button>
                            ))}
                        </div>

                        {error && (
                            <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg flex items-center gap-2">
                                <span className="font-bold">Error:</span> {error}
                            </div>
                        )}

                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <InputField icon={User} label="Full Name" value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} placeholder="John Doe" />
                                <InputField icon={Mail} label="Email" type="email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} placeholder="john@example.com" />
                            </div>

                            <InputField icon={Lock} label="Password" type="password" value={formData.password} onChange={(v) => setFormData({ ...formData, password: v })} placeholder="••••••••" />

                            {/* Role Specific Fields using AnimatePresence for smooth toggle could be nice, keeping it simple for now */}
                            {role === 'student' && (
                                <div className="grid grid-cols-2 gap-4 pt-2 border-t border-slate-100">
                                    <InputField icon={GraduationCap} label="Batch" value={formData.batch} onChange={(v) => setFormData({ ...formData, batch: v })} placeholder="2024" />
                                    <InputField icon={Building} label="Department" value={formData.department} onChange={(v) => setFormData({ ...formData, department: v })} placeholder="CSE" />
                                </div>
                            )}

                            {role === 'alumni' && (
                                <div className="space-y-4 pt-2 border-t border-slate-100">
                                    <div className="grid grid-cols-2 gap-4">
                                        <InputField icon={GraduationCap} label="Batch" value={formData.batch} onChange={(v) => setFormData({ ...formData, batch: v })} placeholder="2024" />
                                        <InputField icon={Building} label="Department" value={formData.department} onChange={(v) => setFormData({ ...formData, department: v })} placeholder="CSE" />
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <InputField icon={Building} label="Company" value={formData.company} onChange={(v) => setFormData({ ...formData, company: v })} placeholder="Google" />
                                        <InputField icon={Briefcase} label="Job Title" value={formData.jobTitle} onChange={(v) => setFormData({ ...formData, jobTitle: v })} placeholder="SDE II" />
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <InputField icon={MapPin} label="Location" value={formData.location} onChange={(v) => setFormData({ ...formData, location: v })} placeholder="New York, USA" />
                                        <InputField icon={Linkedin} label="LinkedIn URL" value={formData.linkedin} onChange={(v) => setFormData({ ...formData, linkedin: v })} placeholder="https://linkedin.com/in/..." />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">Skills (Comma separated)</label>
                                        <input
                                            type="text"
                                            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm font-medium text-slate-900 placeholder:text-slate-400"
                                            placeholder="React, Node.js, Python"
                                            value={formData.skills}
                                            onChange={(e) => setFormData({ ...formData, skills: e.target.value })}
                                        />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="pt-4 flex justify-end gap-3">
                            <button
                                type="button"
                                onClick={onClose}
                                className="px-5 py-2.5 rounded-xl text-slate-600 font-medium hover:bg-slate-50 transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={loading}
                                className="px-6 py-2.5 rounded-xl bg-blue-600 text-white font-medium hover:bg-blue-700 disabled:opacity-70 transition-colors shadow-lg shadow-blue-600/20"
                            >
                                {loading ? 'Creating...' : 'Create User'}
                            </button>
                        </div>
                    </form>
                </motion.div>
            </div>
        </AnimatePresence>
    );
};

const InputField = ({ icon: Icon, label, type = "text", value, onChange, placeholder }) => (
    <div>
        <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">{label}</label>
        <div className="relative">
            <div className="absolute left-3 top-3 text-slate-400">
                <Icon size={18} />
            </div>
            <input
                type={type}
                required
                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm font-medium text-slate-900 placeholder:text-slate-400"
                placeholder={placeholder}
                value={value}
                onChange={(e) => onChange(e.target.value)}
            />
        </div>
    </div>
);

export default AddUserModal;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Save, User, Briefcase, GraduationCap, MapPin, Link as LinkIcon, AlertCircle, Mail, Lock } from 'lucide-react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const EditProfileModal = ({ isOpen, onClose }) => {
    const { user, setUser } = useAuth();
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        confirmPassword: '',
        currentPassword: '',
        bio: '',
        location: '',
        skills: '', // Comma separated string for input
        // Student
        batch: '',
        department: '',
        // Alumni
        company: '',
        jobTitle: '',
        linkedin: ''
    });

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);

    // Initialize form with user data when modal opens
    useEffect(() => {
        if (user && isOpen) {
            setFormData({
                name: user.name || '',
                email: user.email || '',
                password: '', // Always reset password field
                confirmPassword: '',
                currentPassword: '',
                bio: user.bio || '',
                location: user.location || '',
                skills: user.skills ? user.skills.join(', ') : '',
                batch: user.batch || '',
                department: user.department || '',
                company: user.company || '',
                jobTitle: user.jobTitle || '',
                linkedin: user.linkedin || ''
            });
        }
    }, [user, isOpen]);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        // Password Validation
        if (formData.password) {
            if (formData.password !== formData.confirmPassword) {
                setError("New passwords do not match");
                setLoading(false);
                return;
            }
            if (!formData.currentPassword) {
                setError("Please enter your current password to confirm changes");
                setLoading(false);
                return;
            }
        }

        try {
            // Convert skills string back to array
            const skillsArray = formData.skills.split(',').map(s => s.trim()).filter(s => s);

            const payload = {
                ...formData,
                skills: skillsArray
            };

            const { data } = await api.put('/users/profile', payload);

            // Update auth context with new user data
            // Maintain the token from existing user object or the response if backend returns it
            // Safely retrieve token from current user state or localStorage as fallback
            const currentToken = user?.token || JSON.parse(localStorage.getItem('user'))?.token;

            const updatedUser = { ...data, token: currentToken };
            setUser(updatedUser);
            localStorage.setItem('user', JSON.stringify(updatedUser)); // Update local storage

            onClose(); // Close modal on success
        } catch (err) {
            console.error("Profile Update Error:", err);
            // Construct a more descriptive error message
            let errorMessage = 'Failed to update profile';
            if (err.response?.data?.message) {
                errorMessage = err.response.data.message;
            } else if (err.message) {
                errorMessage = err.message;
            }
            setError(errorMessage);
        } finally {
            setLoading(false);
        }
    };

    const isStudent = user?.role === 'student';
    const isAlumni = user?.role === 'alumni';

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 overflow-y-auto"
                    />

                    {/* Modal Container to handle scrolling */}
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none">
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0, y: 20 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 20 }}
                            className="bg-white rounded-2xl shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto pointer-events-auto flex flex-col"
                        >
                            {/* Header */}
                            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10">
                                <h2 className="text-xl font-bold text-slate-900">Edit Profile</h2>
                                <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
                                    <X size={20} />
                                </button>
                            </div>

                            {/* Body */}
                            <div className="p-6 overflow-y-auto">
                                {error && (
                                    <div className="mb-6 p-4 bg-red-50 text-red-600 rounded-xl flex items-center gap-3 text-sm">
                                        <AlertCircle size={18} />
                                        {error}
                                    </div>
                                )}

                                <form id="edit-profile-form" onSubmit={handleSubmit} className="space-y-6">
                                    {/* Basics */}
                                    <div className="grid md:grid-cols-2 gap-6">
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium text-slate-700">Full Name</label>
                                            <div className="relative">
                                                <User className="absolute left-3 top-3 text-slate-400" size={18} />
                                                <input
                                                    type="text"
                                                    name="name"
                                                    value={formData.name}
                                                    onChange={handleChange}
                                                    className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                    placeholder="John Doe"
                                                />
                                            </div>
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium text-slate-700">Location</label>
                                            <div className="relative">
                                                <MapPin className="absolute left-3 top-3 text-slate-400" size={18} />
                                                <input
                                                    type="text"
                                                    name="location"
                                                    value={formData.location}
                                                    onChange={handleChange}
                                                    className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                    placeholder="City, Country"
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Account Settings */}
                                    <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-4">
                                        <h3 className="text-sm font-bold text-slate-700 uppercase tracking-wider">Account Settings</h3>
                                        <div className="space-y-4">
                                            <div className="space-y-2">
                                                <label className="text-sm font-medium text-slate-700">Email Address</label>
                                                <div className="relative">
                                                    <Mail className="absolute left-3 top-3 text-slate-400" size={18} />
                                                    <input
                                                        type="email"
                                                        name="email"
                                                        value={formData.email}
                                                        onChange={handleChange}
                                                        className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                        placeholder="john@example.com"
                                                    />
                                                </div>
                                            </div>

                                            <div className="pt-4 border-t border-slate-200">
                                                <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-3">Change Password</h4>
                                                <div className="grid md:grid-cols-2 gap-4">
                                                    <div className="space-y-2 md:col-span-2">
                                                        <label className="text-sm font-medium text-slate-700">Current Password</label>
                                                        <div className="relative">
                                                            <Lock className="absolute left-3 top-3 text-slate-400" size={18} />
                                                            <input
                                                                type="password"
                                                                name="currentPassword"
                                                                value={formData.currentPassword}
                                                                onChange={handleChange}
                                                                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                                placeholder="Required to set new password"
                                                            />
                                                        </div>
                                                    </div>
                                                    <div className="space-y-2">
                                                        <label className="text-sm font-medium text-slate-700">New Password</label>
                                                        <div className="relative">
                                                            <Lock className="absolute left-3 top-3 text-slate-400" size={18} />
                                                            <input
                                                                type="password"
                                                                name="password"
                                                                value={formData.password}
                                                                onChange={handleChange}
                                                                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                                placeholder="Enter new password"
                                                            />
                                                        </div>
                                                    </div>
                                                    <div className="space-y-2">
                                                        <label className="text-sm font-medium text-slate-700">Confirm New Password</label>
                                                        <div className="relative">
                                                            <Lock className="absolute left-3 top-3 text-slate-400" size={18} />
                                                            <input
                                                                type="password"
                                                                name="confirmPassword"
                                                                value={formData.confirmPassword}
                                                                onChange={handleChange}
                                                                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                                placeholder="Confirm new password"
                                                            />
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <label className="text-sm font-medium text-slate-700">Bio</label>
                                        <textarea
                                            name="bio"
                                            value={formData.bio}
                                            onChange={handleChange}
                                            rows="3"
                                            className="w-full p-4 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700 resize-none"
                                            placeholder="Tell us a bit about yourself..."
                                        />
                                    </div>

                                    {/* Student Specific */}
                                    {isStudent && (
                                        <div className="bg-blue-50/50 p-6 rounded-2xl border border-blue-100 space-y-6">
                                            <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wider flex items-center gap-2">
                                                <GraduationCap size={16} /> Student Details
                                            </h3>
                                            <div className="grid md:grid-cols-2 gap-6">
                                                <div className="space-y-2">
                                                    <label className="text-sm font-medium text-slate-700">Department</label>
                                                    <input
                                                        type="text"
                                                        name="department"
                                                        value={formData.department}
                                                        onChange={handleChange}
                                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                        placeholder="e.g. Computer Science"
                                                    />
                                                </div>
                                                <div className="space-y-2">
                                                    <label className="text-sm font-medium text-slate-700">Batch Year</label>
                                                    <input
                                                        type="text"
                                                        name="batch"
                                                        value={formData.batch}
                                                        onChange={handleChange}
                                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                                        placeholder="e.g. 2025"
                                                    />
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Alumni Specific */}
                                    {isAlumni && (
                                        <div className="bg-amber-50/50 p-6 rounded-2xl border border-amber-100 space-y-6">
                                            <h3 className="text-sm font-bold text-amber-800 uppercase tracking-wider flex items-center gap-2">
                                                <Briefcase size={16} /> Professional Info
                                            </h3>
                                            <div className="grid md:grid-cols-2 gap-6">
                                                <div className="space-y-2">
                                                    <label className="text-sm font-medium text-slate-700">Company</label>
                                                    <input
                                                        type="text"
                                                        name="company"
                                                        value={formData.company}
                                                        onChange={handleChange}
                                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500/20 focus:border-amber-500 transition-all font-medium text-slate-700"
                                                        placeholder="Current Company"
                                                    />
                                                </div>
                                                <div className="space-y-2">
                                                    <label className="text-sm font-medium text-slate-700">Job Title</label>
                                                    <input
                                                        type="text"
                                                        name="jobTitle"
                                                        value={formData.jobTitle}
                                                        onChange={handleChange}
                                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500/20 focus:border-amber-500 transition-all font-medium text-slate-700"
                                                        placeholder="e.g. SDE II"
                                                    />
                                                </div>
                                                <div className="space-y-2 md:col-span-2">
                                                    <label className="text-sm font-medium text-slate-700">LinkedIn URL</label>
                                                    <div className="relative">
                                                        <LinkIcon className="absolute left-3 top-3 text-slate-400" size={18} />
                                                        <input
                                                            type="text"
                                                            name="linkedin"
                                                            value={formData.linkedin}
                                                            onChange={handleChange}
                                                            className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500/20 focus:border-amber-500 transition-all font-medium text-slate-700"
                                                            placeholder="https://linkedin.com/in/..."
                                                        />
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Skills */}
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium text-slate-700">Skills (comma separated)</label>
                                        <input
                                            type="text"
                                            name="skills"
                                            value={formData.skills}
                                            onChange={handleChange}
                                            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-medium text-slate-700"
                                            placeholder="React, Node.js, Design..."
                                        />
                                    </div>

                                </form>
                            </div>

                            {/* Footer */}
                            <div className="p-6 border-t border-slate-100 bg-slate-50 rounded-b-2xl sticky bottom-0 z-10 flex justifying-end">
                                <div className="flex gap-3 ml-auto">
                                    <button
                                        type="button"
                                        onClick={onClose}
