export default EditProfileModal;

import React, { useState, useEffect } from 'react';
import { X, Save } from 'lucide-react';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import api from '../services/api';

const EditQueryModal = ({ isOpen, onClose, query, onQueryUpdated }) => {
    const [formData, setFormData] = useState({
        title: '',
        description: '',
        tags: ''
    });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (query) {
            setFormData({
                title: query.title || '',
                description: query.description || '',
                tags: query.tags ? query.tags.join(', ') : ''
            });
        }
    }, [query]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const payload = {
                title: formData.title,
                description: formData.description,
                tags: formData.tags.split(',').map(tag => tag.trim())
            };

            const { data } = await api.put(`/queries/${query._id}`, payload);
            onQueryUpdated(data);
            onClose();
        } catch (error) {
            console.error("Failed to update query", error);
            toast.error("Failed to update query");
        } finally {
            setLoading(false);
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 transition-all"
                    />
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: 20 }}
                        className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none"
                    >
                        <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl pointer-events-auto overflow-hidden">
                            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                                <h2 className="text-xl font-bold text-slate-900">Edit Query</h2>
                                <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors">
                                    <X size={20} />
                                </button>
                            </div>

                            <form onSubmit={handleSubmit} className="p-6 space-y-6">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">Subject</label>
                                    <input
                                        type="text"
                                        required
                                        className="input-field bg-slate-50"
                                        value={formData.title}
                                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">Description</label>
                                    <textarea
                                        rows={6}
                                        required
                                        className="input-field bg-slate-50 resize-none"
                                        value={formData.description}
                                        onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                    ></textarea>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">Tags</label>
                                    <input
                                        type="text"
                                        className="input-field bg-slate-50"
                                        placeholder="e.g. java, career, placements (Comma separated)"
                                        value={formData.tags}
                                        onChange={(e) => setFormData({ ...formData, tags: e.target.value })}
                                    />
                                </div>

                                <div className="flex justify-end pt-4">
                                    <button
                                        type="button"
                                        onClick={onClose}
                                        className="px-5 py-2.5 text-slate-600 font-medium hover:bg-slate-50 rounded-xl transition-colors mr-3"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        disabled={loading}
                                        className="btn-primary flex items-center gap-2 px-6"
                                    >
                                        <Save size={18} />
                                        {loading ? 'Saving...' : 'Save Changes'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
};

export default EditQueryModal;

import React, { useState, useEffect } from 'react';
import { X, User, Mail, Lock, Briefcase, GraduationCap, Building, MapPin, Linkedin, CheckCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import api from '../services/api';

const EditUserModal = ({ isOpen, onClose, user, onUserUpdated }) => {
    const [role, setRole] = useState('student');
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        batch: '',
        department: '',
        company: '',
        jobTitle: '',
        location: '',
        linkedin: '',
        skills: '',
        isVerified: false
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (user) {
            setRole(user.role);
            setFormData({
                name: user.name || '',
                email: user.email || '',
                batch: user.batch || '',
                department: user.department || '',
                company: user.company || '',
                jobTitle: user.jobTitle || '',
                location: user.location || '',
                linkedin: user.linkedin || '',
                skills: user.skills ? user.skills.join(', ') : '',
                isVerified: user.isVerified || false
            });
        }
    }, [user, isOpen]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const payload = {
                ...formData,
                role,
                skills: formData.skills ? formData.skills.split(',').map(s => s.trim()) : []
            };

            // Password is not being updated here for simplicity, but could be added if needed

            await api.put(`/users/${user._id}`, payload); // This hits the new admin route
            onUserUpdated();
            onClose();
        } catch (err) {
            console.error("Failed to update user", err);
            setError(err.response?.data?.message || 'Failed to update user');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
                />

                <motion.div
                    initial={{ opacity: 0, scale: 0.95, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95, y: 20 }}
                    className="relative w-full max-w-lg bg-white rounded-2xl shadow-xl overflow-hidden max-h-[90vh] overflow-y-auto"
                >
                    {/* Header */}
                    <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 sticky top-0 z-10 backdrop-blur-sm">
                        <h2 className="text-xl font-bold text-slate-900">Edit User</h2>
                        <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-slate-600">
                            <X size={20} />
                        </button>
                    </div>

                    <form onSubmit={handleSubmit} className="p-8 space-y-6">
                        {/* Role Selector */}
                        <div className="grid grid-cols-3 gap-2 p-1 bg-slate-100 rounded-xl">
                            {['student', 'alumni', 'admin'].map((r) => (
                                <button
                                    key={r}
                                    type="button"
                                    onClick={() => setRole(r)}
                                    className={`py-2 px-4 rounded-lg text-sm font-semibold capitalize transition-all ${role === r ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                                        }`}
                                >
                                    {r}
                                </button>
                            ))}
                        </div>

                        {error && (
                            <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg flex items-center gap-2">
                                <span className="font-bold">Error:</span> {error}
                            </div>
                        )}

                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <InputField icon={User} label="Full Name" value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} placeholder="John Doe" />
                                <InputField icon={Mail} label="Email" type="email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} placeholder="john@example.com" />
                            </div>

                            {/* Verify Toggle for Alumni */}
                            {role === 'alumni' && (
                                <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                                    <div className={`w-5 h-5 rounded flex items-center justify-center cursor-pointer transition-colors ${formData.isVerified ? 'bg-green-500 text-white' : 'bg-slate-200'}`}
                                        onClick={() => setFormData({ ...formData, isVerified: !formData.isVerified })}
                                    >
                                        {formData.isVerified && <CheckCircle size={14} />}
                                    </div>
                                    <span className="text-sm font-medium text-slate-700" onClick={() => setFormData({ ...formData, isVerified: !formData.isVerified })}>
                                        Verified Alumni
                                    </span>
                                </div>
                            )}

                            {/* Role Specific Fields */}
                            {(role === 'student' || role === 'alumni') && (
                                <div className="grid grid-cols-2 gap-4 pt-2 border-t border-slate-100">
                                    <InputField icon={GraduationCap} label="Batch" value={formData.batch} onChange={(v) => setFormData({ ...formData, batch: v })} placeholder="2024" />
                                    <InputField icon={Building} label="Department" value={formData.department} onChange={(v) => setFormData({ ...formData, department: v })} placeholder="CSE" />
                                </div>
                            )}

                            {role === 'alumni' && (
                                <div className="space-y-4 pt-2 border-t border-slate-100">
                                    <div className="grid grid-cols-2 gap-4">
                                        <InputField icon={Building} label="Company" value={formData.company} onChange={(v) => setFormData({ ...formData, company: v })} placeholder="Google" />
                                        <InputField icon={Briefcase} label="Job Title" value={formData.jobTitle} onChange={(v) => setFormData({ ...formData, jobTitle: v })} placeholder="SDE II" />
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <InputField icon={MapPin} label="Location" value={formData.location} onChange={(v) => setFormData({ ...formData, location: v })} placeholder="New York, USA" />
                                        <InputField icon={Linkedin} label="LinkedIn URL" value={formData.linkedin} onChange={(v) => setFormData({ ...formData, linkedin: v })} placeholder="https://linkedin.com/in/..." />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">Skills (Comma separated)</label>
                                        <input
                                            type="text"
                                            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm font-medium text-slate-900 placeholder:text-slate-400"
                                            placeholder="React, Node.js, Python"
                                            value={formData.skills}
                                            onChange={(e) => setFormData({ ...formData, skills: e.target.value })}
                                        />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="pt-4 flex justify-end gap-3">
                            <button
                                type="button"
                                onClick={onClose}
                                className="px-5 py-2.5 rounded-xl text-slate-600 font-medium hover:bg-slate-50 transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={loading}
                                className="px-6 py-2.5 rounded-xl bg-blue-600 text-white font-medium hover:bg-blue-700 disabled:opacity-70 transition-colors shadow-lg shadow-blue-600/20"
                            >
                                {loading ? 'Saving...' : 'Save Changes'}
                            </button>
                        </div>
                    </form>
                </motion.div>
            </div>
        </AnimatePresence>
    );
};

const InputField = ({ icon: Icon, label, type = "text", value, onChange, placeholder }) => (
    <div>
        <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1.5">{label}</label>
        <div className="relative">
            <div className="absolute left-3 top-3 text-slate-400">
                <Icon size={18} />
            </div>
            <input
                type={type}
                required
                className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm font-medium text-slate-900 placeholder:text-slate-400"
                placeholder={placeholder}
                value={value}
                onChange={(e) => onChange(e.target.value)}
            />
        </div>
    </div>
);

