import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Bell, Check, Clock } from 'lucide-react';

const NotificationPopup = ({
    isOpen,
    onClose,
    notifications = [],
    loading = false,
    markAsRead,
    markAllAsRead
}) => {
    const navigate = useNavigate();

    const handleNotificationClick = (notif) => {
        if (!notif.read && markAsRead) {
            markAsRead(notif._id);
        }
        if (notif.link) {
            navigate(notif.link);
        }
        onClose();
    };

    if (!isOpen) return null;

    return (
        <div className="absolute top-12 right-0 w-80 md:w-96 z-50">
            {/* Backdrop for click-outside (transparent) */}
            <div className="fixed inset-0 z-40" onClick={onClose}></div>

            <motion.div
                initial={{ opacity: 0, scale: 0.95, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95, y: 10 }}
                transition={{ duration: 0.2 }}
                className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden relative z-50"
            >
                {/* Header */}
                <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <Bell size={16} className="text-blue-600" /> Notifications
                    </h3>
                    {notifications.some(n => !n.read) && (
                        <button
                            onClick={markAllAsRead}
                            className="text-xs font-medium text-blue-600 hover:text-blue-700 hover:underline"
                        >
                            Mark all as read
                        </button>
                    )}
                </div>

                {/* List */}
                <div className="max-h-[400px] overflow-y-auto">
                    {loading ? (
                        <div className="p-8 text-center text-slate-400">Loading...</div>
                    ) : notifications.length > 0 ? (
                        notifications.map((notif) => (
                            <div
                                key={notif._id}
                                onClick={() => handleNotificationClick(notif)}
                                className={`p-4 border-b border-slate-50 hover:bg-slate-50 transition-colors cursor-pointer ${!notif.read ? 'bg-blue-50/30' : ''}`}
                            >
                                <div className="flex gap-3">
                                    <div className={`mt-1 p-1.5 rounded-full shrink-0 ${notif.type === 'reply' ? 'bg-green-100 text-green-600' :
                                        notif.type === 'badge' ? 'bg-amber-100 text-amber-600' :
                                            'bg-blue-100 text-blue-600'
                                        }`}>
                                        {notif.type === 'reply' ? <Check size={14} /> :
                                            notif.type === 'badge' ? <Clock size={14} /> :
                                                <Bell size={14} />}
                                    </div>
                                    <div>
                                        <h4 className={`text-sm font-semibold mb-0.5 ${!notif.read ? 'text-slate-900' : 'text-slate-600'}`}>
                                            {notif.title}
                                        </h4>
                                        <p className="text-xs text-slate-500 leading-relaxed mb-1.5">
                                            {notif.message}
                                        </p>
                                        <span className="text-[10px] font-medium text-slate-400 flex items-center gap-1">
                                            <Clock size={10} /> {notif.time ? notif.time : new Date(notif.createdAt).toLocaleDateString()}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="p-8 text-center text-slate-400">
                            <Bell size={32} className="mx-auto mb-3 opacity-20" />
                            <p className="text-sm">No new notifications</p>
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="p-3 bg-slate-50 border-t border-slate-100 text-center">
                    <button onClick={onClose} className="text-xs font-medium text-slate-500 hover:text-slate-700">
                        Close
                    </button>
                </div>
            </motion.div>
        </div>
    );
};

export default NotificationPopup;

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, CheckCircle2, Star, Target, MessageCircle, UserCheck, History, Award } from 'lucide-react';
import api from '../services/api';
import moment from 'moment';

const PointsHistoryModal = ({ isOpen, onClose, points, level, user }) => {
    const [history, setHistory] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (isOpen) {
            fetchHistory();
        }
    }, [isOpen]);

    const fetchHistory = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/users/gamification/history');
            setHistory(data);
        } catch (error) {
            console.error("Failed to fetch history", error);
        } finally {
            setLoading(false);
        }
    };

    // Define earnable actions
    const earnActions = [
        { icon: UserCheck, label: 'Complete Profile', points: 50, completed: user?.isProfileCompleteAwarded },
        { icon: MessageCircle, label: 'Answer a Query', points: 20, completed: false },
        { icon: CheckCircle2, label: 'Get Answer Accepted', points: 50, completed: false },
        { icon: Star, label: 'Receive a Like', points: 10, completed: false },
    ];

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 transition-opacity"
                    />

                    {/* Modal */}
                    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none">
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0, y: 20 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 20 }}
                            className="bg-white rounded-2xl shadow-2xl w-full max-w-md pointer-events-auto overflow-hidden flex flex-col max-h-[85vh]"
                        >
                            {/* Header with Gradient */}
                            <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-6 text-white relative shrink-0">
                                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl -translate-y-1/2 translate-x-1/2"></div>

                                <div className="flex justify-between items-start relative z-10">
                                    <div>
                                        <h2 className="text-2xl font-bold">Your Journey</h2>
                                        <p className="text-blue-100 opacity-90 font-medium">Current Level: {level.label}</p>
                                    </div>
                                    <button onClick={onClose} className="p-2 bg-white/20 hover:bg-white/30 rounded-full transition-colors backdrop-blur-md">
                                        <X size={20} />
                                    </button>
                                </div>

                                <div className="mt-6 flex items-baseline gap-2">
                                    <span className="text-4xl font-bold">{points}</span>
                                    <span className="text-blue-200">Total Points</span>
                                </div>
                            </div>

                            {/* Scrollable Content */}
                            <div className="p-6 overflow-y-auto custom-scrollbar">
                                {/* Recent Activity Section */}
                                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                                    <History size={16} /> Recent Activity
                                </h3>

                                <div className="space-y-3 mb-8">
                                    {loading ? (
                                        <p className="text-sm text-slate-500 text-center py-4">Loading history...</p>
                                    ) : history.length > 0 ? (
                                        history.map((item) => (
                                            <div key={item._id} className="flex items-center gap-4 p-3 bg-slate-50 rounded-xl border border-slate-100">
                                                <div className="p-2 bg-white rounded-full text-indigo-500 shadow-sm">
                                                    <Award size={18} />
                                                </div>
                                                <div className="flex-1">
                                                    <p className="text-slate-900 font-medium text-sm">{item.action}</p>
                                                    <p className="text-xs text-slate-400">{moment(item.createdAt).fromNow()}</p>
                                                </div>
