                            <User size={24} className={role === 'student' ? 'text-blue-600' : 'text-slate-400'} />
                            <span className={`font-medium ${role === 'student' ? 'text-blue-900' : 'text-slate-600'}`}>I am a Student</span>
                            {role === 'student' && <CheckCircle2 size={16} className="text-blue-600" />}
                        </div>
                        <div
                            onClick={() => setRole('alumni')}
                            className={`p-4 rounded-xl border-2 cursor-pointer transition-all flex flex-col items-center gap-2 ${role === 'alumni' ? 'border-blue-600 bg-blue-50/50' : 'border-slate-100 hover:border-slate-200'
                                }`}
                        >
                            <GraduationCap size={24} className={role === 'alumni' ? 'text-blue-600' : 'text-slate-400'} />
                            <span className={`font-medium ${role === 'alumni' ? 'text-blue-900' : 'text-slate-600'}`}>I am an Alumni</span>
                            {role === 'alumni' && <CheckCircle2 size={16} className="text-blue-600" />}
                        </div>
                    </div>

                    <form onSubmit={handleRegister} className="grid md:grid-cols-2 gap-6">
                        {error && (
                            <div className="md:col-span-2 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 text-center">
                                {error}
                            </div>
                        )}
                        <div className="space-y-1">
                            <label className="text-sm font-medium text-slate-700">Full Name</label>
                            <div className="relative">
                                <User className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                <input
                                    type="text"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    className="input-field !pl-11"
                                    placeholder="John Doe"
                                    required
                                />
                            </div>
                        </div>
                        <div className="space-y-1">
                            <label className="text-sm font-medium text-slate-700">Email Address</label>
                            <div className="relative">
                                <Mail className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                <input
                                    type="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    className="input-field !pl-11"
                                    placeholder="john@college.edu"
                                    required
                                />
                            </div>
                        </div>
                        <div className="space-y-1">
                            <label className="text-sm font-medium text-slate-700">Password</label>
                            <div className="relative">
                                <Lock className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                <input
                                    type="password"
                                    name="password"
                                    value={formData.password}
                                    onChange={handleChange}
                                    className="input-field !pl-11"
                                    placeholder="••••••••"
                                    required
                                />
                            </div>
                        </div>

                        <div className="space-y-1">
                            <label className="text-sm font-medium text-slate-700">{role === 'alumni' ? 'Graduation Batch' : 'Current Batch'}</label>
                            <div className="relative">
                                <BookOpen className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                <input
                                    type="text"
                                    name="batch"
                                    value={formData.batch}
                                    onChange={handleChange}
                                    className="input-field !pl-11"
                                    placeholder={role === 'alumni' ? 'e.g. 2024' : 'e.g. 2023-2027'}
                                />
                            </div>
                        </div>

                        <div className="space-y-1">
                            <label className="text-sm font-medium text-slate-700">Department</label>
                            <div className="relative">
                                <Building className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                <input
                                    type="text"
                                    name="department"
                                    value={formData.department}
                                    onChange={handleChange}
                                    className="input-field !pl-11"
                                    placeholder="CSE"
                                />
                            </div>
                        </div>

                        {role === 'alumni' && (
                            <>
                                <div className="space-y-1">
                                    <label className="text-sm font-medium text-slate-700">Current Company</label>
                                    <div className="relative">
                                        <Building className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                        <input
                                            type="text"
                                            name="company"
                                            value={formData.company}
                                            onChange={handleChange}
                                            className="input-field !pl-11"
                                            placeholder="Google, Microsoft..."
                                        />
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <label className="text-sm font-medium text-slate-700">Job Title</label>
                                    <div className="relative">
                                        <Briefcase className="absolute left-3 top-3.5 text-slate-400" size={18} />
                                        <input
                                            type="text"
                                            name="jobTitle"
                                            value={formData.jobTitle}
                                            onChange={handleChange}
                                            className="input-field !pl-11"
                                            placeholder="Software Engineer"
                                        />
                                    </div>
                                </div>
                            </>
                        )}

                        <div className="md:col-span-2 pt-4">
                            <button type="submit" className="btn-primary w-full">Create Account</button>
                        </div>
                    </form>

                    <p className="text-center mt-6 text-slate-600 text-sm">
                        Already have an account? <Link to="/login" className="text-blue-600 font-medium hover:underline">Sign In</Link>
                    </p>
                </motion.div>
            </div>
        </div>
    );
};

export default Register;

import React, { useEffect, useState } from 'react';
import { Check, X, Building, GraduationCap, MapPin } from 'lucide-react';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';
import api from '../../services/api';

const VerifyUsers = () => {
    const [pendingUsers, setPendingUsers] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchPending = async () => {
        try {
            const { data } = await api.get('/admin/users');
            const pending = data.filter(u => u.role === 'alumni' && !u.isVerified);
            setPendingUsers(pending);
        } catch (error) {
            console.error("Failed to fetch pending users", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPending();
    }, []);

    const handleApprove = async (id) => {
        try {
            await api.put(`/admin/users/${id}/verify`);
            // Optimistic Update
            setPendingUsers(pendingUsers.filter(u => u._id !== id));
        } catch (error) {
            console.error("Failed to approve user", error);
            toast.error("Failed to verify user");
        }
    };

    const handleReject = async (id) => {
        if (!window.confirm("Rejecting will delete this user account. Are you sure?")) return;
        try {
            await api.delete(`/admin/users/${id}`);
            setPendingUsers(pendingUsers.filter(u => u._id !== id));
        } catch (error) {
            console.error("Failed to reject user", error);
        }
    };

    if (loading) return <div className="p-8 text-center text-slate-500">Loading requests...</div>;

    return (
        <div className="max-w-5xl">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h2 className="text-2xl font-bold text-slate-900">Verification Requests</h2>
                    <p className="text-slate-500">Review and approve new member registrations</p>
                </div>
                <div className="bg-blue-100 text-blue-700 px-4 py-2 rounded-lg text-sm font-bold">
                    {pendingUsers.length} Pending
                </div>
            </div>

            <div className="grid md:grid-cols-2 gap-6">
                {pendingUsers.length > 0 ? (
                    pendingUsers.map((user) => (
                        <motion.div
                            key={user._id}
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center font-bold text-lg text-slate-600 uppercase">
                                        {user.name ? user.name[0] : 'U'}
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-slate-900 text-lg">{user.name}</h3>
                                        <span className="text-[10px] uppercase font-bold px-2 py-0.5 rounded bg-purple-100 text-purple-700">
                                            Alumni
                                        </span>
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-3 bg-slate-50 p-4 rounded-xl mb-6">
                                <div className="flex items-center gap-3 text-sm text-slate-600">
                                    <Building size={16} className="text-slate-400" />
                                    <span className="font-medium">{user.jobTitle || 'N/A'} @ {user.company || 'N/A'}</span>
                                </div>
                                <div className="flex items-center gap-3 text-sm text-slate-600">
                                    <GraduationCap size={16} className="text-slate-400" />
                                    <span>Batch {user.batch || 'N/A'}</span>
                                </div>
                                <div className="flex items-center gap-3 text-sm text-slate-600">
                                    <MapPin size={16} className="text-slate-400" />
                                    <span>{user.location || 'Unknown Location'}</span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    className="flex items-center justify-center gap-2 py-2.5 rounded-xl border border-red-200 text-red-600 font-medium hover:bg-red-50 transition-colors"
                                    onClick={() => handleReject(user._id)}
                                >
                                    <X size={18} /> Reject
                                </button>
                                <button
                                    className="flex items-center justify-center gap-2 py-2.5 rounded-xl bg-slate-900 text-white font-medium hover:bg-slate-800 transition-colors shadow-lg shadow-slate-900/10"
                                    onClick={() => handleApprove(user._id)}
                                >
                                    <Check size={18} /> Approve
                                </button>
                            </div>
                        </motion.div>
                    ))
                ) : (
                    <div className="col-span-full text-center py-10 bg-white rounded-xl border border-slate-200 text-slate-500">
                        No pending verifications. All good!
                    </div>
                )}
            </div>
        </div>
    );
};

export default VerifyUsers;

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { MessageCircle, ThumbsUp, Award, ArrowRight } from 'lucide-react';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { Link } from 'react-router-dom';
import BadgeDisplay from '../../components/BadgeDisplay';
import PointsProgressWidget from '../../components/PointsProgressWidget';
import PageTransition from '../../components/ui/PageTransition';
import Card from '../../components/ui/Card';
import StatCard from '../../components/ui/StatCard';
import Button from '../../components/ui/Button';

const AlumniDashboard = () => {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        answered: 0,
        helpful: 0,
        reputation: 0
    });
    const [recommendedQueries, setRecommendedQueries] = useState([]);
    const [topMentors, setTopMentors] = useState([]);
    const [roadplan, setRoadplan] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch Queries
                const { data: queries } = await api.get('/queries');

                // Fetch Latest User Data
                const { data: userData } = await api.get('/auth/me');
                setRoadplan(userData.roadplan || []);

                // Fetch Leaderboard
                const { data: leaderboard } = await api.get('/gamification/leaderboard');
                setTopMentors(leaderboard.slice(0, 5));

                // Calculate Stats
                let answeredCount = 0;
                let helpfulCount = 0;
                queries.forEach(q => {
                    const userResponses = q.responses?.filter(r => r.author === user._id || r.author?._id === user._id) || [];
                    if (userResponses.length > 0) {
                        answeredCount += userResponses.length;
                        userResponses.forEach(r => {
                            if (r.upvotes) {
                                helpfulCount += r.upvotes.length;
                            }
                        });
                    }
                });

                setStats({
                    answered: answeredCount,
                    helpful: helpfulCount,
                    reputation: userData.points || 0
                });

                // Recommended Queries
                const pending = queries.filter(q => q.status !== 'Resolved' && q.author !== user._id);
                setRecommendedQueries(pending.slice(0, 3));

            } catch (error) {
                console.error("Error fetching alumni dashboard data", error);
            } finally {
                setLoading(false);
            }
        };

        if (user) fetchData();
    }, [user]);

    // Animation Variants
    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: {
                staggerChildren: 0.2
            }
        }
    };

    const item = {
        hidden: { opacity: 0, y: 20 },
        show: {
            opacity: 1,
            y: 0,
            transition: {
                duration: 0.5,
                ease: "easeOut"
            }
        }
    };

    if (loading) return <div className="p-8 text-center text-slate-500">Loading dashboard...</div>;

    return (
        <PageTransition className="space-y-8">
            {/* Overview Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard
                    icon={<MessageCircle size={24} />}
                    label="Queries Answered"
                    value={stats.answered}
                    trend="Keep it up!"
                    color="blue"
                />
                <StatCard
                    icon={<ThumbsUp size={24} />}
                    label="Helpful Votes"
                    value={stats.helpful}
                    trend="Based on feedback"
                    color="green"
                />
                <StatCard
                    icon={<Award size={24} />}
                    label="Community Points"
                    value={stats.reputation}
                    trend={`Level ${Math.floor(stats.reputation / 100) + 1} Mentor`}
                    color="amber"
                />
            </div>

            <div className="grid md:grid-cols-3 gap-8">
                {/* Main Feed Preview */}
                <div className="md:col-span-2 space-y-6">
                    <div className="flex items-center justify-between">
                        <h3 className="text-xl font-bold text-slate-900 tracking-tight">Recommended for You</h3>
                        <Link to="/alumni/feed" className="text-blue-600 font-medium text-sm hover:underline flex items-center gap-1">
                            View All <ArrowRight size={14} />
                        </Link>
                    </div>

                    {/* Query Cards */}
                    <motion.div
                        className="space-y-4"
                        variants={container}
                        initial="hidden"
                        animate="show"
                    >
                        {recommendedQueries.length > 0 ? (
                            recommendedQueries.map((q, i) => (
                                <Card
                                    key={q._id}
                                    variant="glass"
                                    className="group cursor-pointer"
                                    variants={item}
                                    whileHover={{ borderColor: 'rgba(59, 130, 246, 0.5)', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)' }}
                                >
                                    <div className="flex gap-2 mb-3">
                                        {q.tags && q.tags.map((tag, i) => (
                                            <span key={i} className="text-xs font-medium px-2.5 py-1 bg-slate-100/80 text-slate-600 rounded-lg backdrop-blur-sm">
                                                {tag}
                                            </span>
                                        ))}
                                    </div>
                                    <h4 className="text-lg font-bold text-slate-900 mb-2 group-hover:text-blue-600 transition-colors">
                                        {q.title}
                                    </h4>
                                    <p className="text-slate-600 text-sm mb-5 line-clamp-2 leading-relaxed">
                                        {q.description}
                                    </p>
                                    <div className="flex items-center justify-between pt-4 border-t border-slate-100">
                                        <span className="text-xs font-medium text-slate-400">
                                            Posted by <span className="text-slate-600">{q.author?.name || 'Student'}</span> • {new Date(q.createdAt).toLocaleDateString()}
                                        </span>
                                        <Link to={`/alumni/feed`}>
                                            <Button size="sm" variant="primary">Write Answer</Button>
                                        </Link>
                                    </div>
                                </Card>
                            ))
                        ) : (
                            <Card variant="solid" className="text-center py-10">
                                <p className="text-slate-500">No pending queries found.</p>
                            </Card>
                        )}
                    </motion.div>
                </div>

                {/* Sidebar - Leaderboard & Progress */}
                <div className="space-y-6">
                    {/* Points Progress Widget */}
                    <PointsProgressWidget points={stats.reputation} user={user} />

                    <Card variant="solid">
                        <h3 className="text-lg font-bold text-slate-900 mb-5 flex items-center gap-2">
                            <Award className="text-amber-500" size={20} />
                            Top Mentors
                        </h3>
                        <div className="space-y-4">
                            {topMentors.length > 0 ? (
                                topMentors.map((mentor, i) => (
                                    <div key={mentor._id} className="flex items-center gap-3 p-2 rounded-xl hover:bg-slate-50 transition-colors">
                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-xs ${i === 0 ? 'bg-amber-100 text-amber-700 ring-2 ring-amber-100' : 'bg-slate-100 text-slate-600'
                                            }`}>
                                            #{i + 1}
                                        </div>
                                        <div className="flex-1">
                                            <h5 className="text-sm font-bold text-slate-900">{mentor.name}</h5>
                                            <div className="flex items-center gap-2 mt-0.5">
                                                <BadgeDisplay badge={mentor.badges?.[mentor.badges.length - 1] || 'Rookie'} size="sm" />
                                                <span className="text-xs text-slate-500 font-medium">• {mentor.points} pts</span>
                                            </div>
                                        </div>
                                        {i === 0 && <Award size={16} className="text-amber-500" />}
                                    </div>
                                ))
                            ) : (
                                <p className="text-sm text-slate-500">No data available yet.</p>
                            )}
                        </div>
                    </Card>
                </div>
            </div>
        </PageTransition>
    );
};

export default AlumniDashboard;

import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { User, Mail, Briefcase, MapPin, Save, Link as LinkIcon } from 'lucide-react';
import { motion } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import EditProfileModal from '../../components/EditProfileModal';
import BadgeDisplay from '../../components/BadgeDisplay';

const AlumniProfile = () => {
    const { user: authUser } = useAuth();
    const [user, setUser] = useState(authUser);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);

    // Fetch latest user data when component mounts
    React.useEffect(() => {
        const fetchLatestUserData = async () => {
            try {
                const { data } = await api.get('/auth/me');
                setUser(data);
            } catch (error) {
                console.error("Error fetching latest user data", error);
            }
        };
        fetchLatestUserData();
    }, []);

    if (!user) return null;

    return (
        <div className="max-w-4xl mx-auto">
            <div className="mb-8">
                {/* Profile Header - Contained in Blue Background */}
                <div className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-8 flex items-center gap-6 shadow-lg relative overflow-hidden">
                    {/* Background Pattern/Deco */}
                    <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>

                    {/* Background Pattern 2 (Alumni specific differentiation - Amber hint) */}
                    <div className="absolute bottom-0 left-0 w-48 h-48 bg-amber-500/10 rounded-full blur-3xl translate-y-1/2 -translate-x-1/2"></div>

                    {/* Avatar */}
                    <div className="w-24 h-24 rounded-full border-4 border-white/30 bg-white/20 backdrop-blur-sm flex items-center justify-center text-white text-3xl font-bold shrink-0 shadow-inner">
                        {user.name.charAt(0)}
                    </div>

                    {/* Info */}
                    <div className="flex-1 relative z-10">
                        <h1 className="text-3xl font-bold text-white mb-1.5">{user.name}</h1>
                        <p className="text-blue-100 font-medium text-lg flex items-center gap-2">
                            <span className="bg-white/20 px-3 py-1 rounded-full text-sm backdrop-blur-md border border-white/10 flex items-center gap-2">
                                <Briefcase size={14} />
                                {user.jobTitle ? user.jobTitle : 'Alumni'}
                            </span>
                            {user.company && (
                                <span className="opacity-90 flex items-center gap-1">
                                    at <span className="font-semibold text-white">{user.company}</span>
                                </span>
                            )}
                        </p>
                    </div>

                    {/* Edit Button */}
                    <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.3 }}
                        onClick={() => setIsEditModalOpen(true)}
                        className="bg-white text-blue-600 hover:bg-blue-50 font-semibold px-5 py-2.5 rounded-xl shadow-lg shadow-blue-900/20 flex items-center gap-2 relative z-10"
                    >
                        <Save size={18} />
                        Edit Profile
                    </motion.button>
                </div>
            </div>

            <div className="grid md:grid-cols-3 gap-8">
                {/* Left Column - Info */}
                <div className="md:col-span-2 space-y-6">
                    <section className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                        <h3 className="text-lg font-bold text-slate-900 mb-6">Personal Information</h3>
                        <div className="space-y-4">
                            <ProfileField icon={User} label="Full Name" value={user.name} />
                            <ProfileField icon={Mail} label="Email Address" value={user.email} />
                            <ProfileField icon={MapPin} label="Location" value={user.location || 'Not updated'} />
                            {user.bio && (
                                <div className="pt-4 border-t border-slate-100 mt-4">
                                    <h4 className="text-xs text-slate-400 font-medium uppercase tracking-wide mb-2">Bio</h4>
                                    <p className="text-slate-600 leading-relaxed">{user.bio}</p>
                                </div>
                            )}
                        </div>
                    </section>

                    <section className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                        <h3 className="text-lg font-bold text-slate-900 mb-6">Professional Details</h3>
                        <div className="space-y-4">
                            <ProfileField icon={Briefcase} label="Current Role" value={`${user.jobTitle || 'N/A'} at ${user.company || 'N/A'}`} />
                            <div className="flex items-center gap-4 p-3 rounded-lg hover:bg-slate-50 transition-colors">
                                <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                                    <LinkIcon size={20} />
                                </div>
                                <div>
                                    <p className="text-xs text-slate-400 font-medium uppercase tracking-wide">LinkedIn Profile</p>
                                    {user.linkedin ? (
                                        <a
                                            href={user.linkedin}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="text-blue-600 font-medium hover:underline flex items-center gap-1"
                                        >
                                            View Profile
                                        </a>
                                    ) : (
                                        <p className="text-slate-900 font-medium">Not connected</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    </section>
                </div>

