                                <div className="pt-4 border-t border-slate-100 mt-4">
                                    <h4 className="text-xs text-slate-400 font-medium uppercase tracking-wide mb-2">Bio</h4>
                                    <p className="text-slate-600 leading-relaxed">{user.bio}</p>
                                </div>
                            )}
                        </div>
                    </section>

                    <section className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                        <h3 className="text-lg font-bold text-slate-900 mb-6">Academic Stats</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="p-4 bg-slate-50 rounded-xl text-center">
                                <div className="text-2xl font-bold text-blue-600">{user.points || 0}</div>
                                <div className="text-xs text-slate-500 uppercase tracking-wide font-medium mt-1">Community Points</div>
                            </div>
                            <div className="p-4 bg-slate-50 rounded-xl text-center">
                                <div className="text-2xl font-bold text-green-600">{user.badges ? user.badges.length : 0}</div>
                                <div className="text-xs text-slate-500 uppercase tracking-wide font-medium mt-1">Badges Earned</div>
                            </div>
                        </div>
                    </section>
                </div>

                {/* Right Column - Skills/Badges */}
                <div className="space-y-6">
                    <section className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                        <h3 className="text-lg font-bold text-slate-900 mb-4">Skills</h3>
                        <div className="flex flex-wrap gap-2">
                            {user.skills && user.skills.length > 0 ? (
                                user.skills.map((skill, index) => (
                                    <span key={index} className="px-3 py-1 rounded-full bg-slate-100 text-slate-700 text-sm font-medium">
                                        {skill}
                                    </span>
                                ))
                            ) : (
                                <span className="text-slate-400 text-sm">No skills added yet</span>
                            )}
                        </div>
                    </section>
                </div>
            </div>

            <EditProfileModal
                isOpen={isEditModalOpen}
                onClose={() => setIsEditModalOpen(false)}
            />
        </div>
    );
};

const ProfileField = ({ icon: Icon, label, value }) => (
    <div className="flex items-center gap-4 p-3 rounded-lg hover:bg-slate-50 transition-colors">
        <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
            <Icon size={20} />
        </div>
        <div>
            <p className="text-xs text-slate-400 font-medium uppercase tracking-wide">{label}</p>
            <p className="text-slate-900 font-medium">{value}</p>
        </div>
    </div>
);

export default StudentProfile;

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { MessageCircle, CheckCircle, Clock } from 'lucide-react';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';

import { motion } from 'framer-motion';
import PageTransition from '../../components/ui/PageTransition';

const StudentQueries = () => {
    const { user } = useAuth();
    const [queries, setQueries] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchQueries = async () => {
            try {
                const { data } = await api.get('/queries');
                // Filter to only show queries by this student
                // (Ideally backend should support /queries/my endpoint, but filtering here works for MVP)
                const myQueries = data.filter(q => q.author === user._id || q.author?._id === user._id);
                setQueries(myQueries);
            } catch (error) {
                console.error("Failed to fetch queries", error);
            } finally {
                setLoading(false);
            }
        };

        if (user) {
            fetchQueries();
        }
    }, [user]);

    if (loading) return <div className="p-8 text-center text-slate-500">Loading your queries...</div>;

    // Animation Variants
    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: {
                staggerChildren: 0.15 // Slower cascade
            }
        }
    };

    const item = {
        hidden: { opacity: 0, y: 20 },
        show: {
            opacity: 1,
            y: 0,
            transition: {
                duration: 0.5, // Gradual fade/slide
                ease: "easeOut"
            }
        }
    };

    return (
        <PageTransition className="space-y-6">
            <h2 className="text-2xl font-bold text-slate-900">My Queries</h2>

            <motion.div
                className="space-y-4"
                variants={container}
                initial="hidden"
                animate="show"
            >
                {queries.length > 0 ? (
                    queries.map((q) => (
                        <motion.div
                            key={q._id}
                            variants={item}
                            whileHover={{ borderColor: 'rgba(59, 130, 246, 0.5)', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)' }}
                            className="bg-white p-6 rounded-2xl border border-slate-200 cursor-pointer group"
                        >
                            <div className="flex items-start justify-between mb-4">
                                <div>
                                    <h3 className="text-lg font-bold text-slate-900 mb-2 group-hover:text-blue-600 transition-colors">{q.title}</h3>
                                    <div className="flex gap-2">
                                        {q.tags && q.tags.map((tag, index) => (
                                            <span key={index} className="px-2 py-1 bg-slate-100 text-slate-600 text-xs rounded-md font-medium">
                                                {tag}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                                <span className={`px-3 py-1 rounded-full text-sm font-medium flex items-center gap-2 ${q.status === 'Resolved' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                                    }`}>
                                    {q.status === 'Resolved' ? <CheckCircle size={16} /> : <Clock size={16} />}
                                    {q.status || 'Pending'}
                                </span>
                            </div>

                            <div className="flex items-center gap-4 text-sm text-slate-500 pt-4 border-t border-slate-100">
                                <span className="flex items-center gap-1">
                                    <MessageCircle size={16} /> {q.responses ? q.responses.length : 0} Responses
                                </span>
                                <span>•</span>
                                <span>Posted {new Date(q.createdAt).toLocaleDateString()}</span>

                                <Link
                                    to={`/student/queries/${q._id}`}
                                    className="ml-auto text-blue-600 font-medium hover:underline"
                                >
                                    View Discussion
                                </Link>
                            </div>
                        </motion.div>
                    ))
                ) : (
                    <motion.div variants={item} className="text-center py-10 bg-white rounded-2xl border border-slate-200">
                        <p className="text-slate-500">You haven't asked any queries yet.</p>
                    </motion.div>
                )}
            </motion.div>
        </PageTransition>
    );
};

export default StudentQueries;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Search, Filter, MapPin, Briefcase } from 'lucide-react';
import api from '../../services/api';
import BadgeDisplay from '../../components/BadgeDisplay';
import { motion } from 'framer-motion';
import PageTransition from '../../components/ui/PageTransition';

const ViewAlumni = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [alumni, setAlumni] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchAlumni = async () => {
            try {
                const { data } = await api.get('/users/alumni');
                setAlumni(data);
            } catch (error) {
                console.error("Failed to fetch alumni", error);
            } finally {
                setLoading(false);
            }
        };
        fetchAlumni();
    }, []);

    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: 0.1 }
        }
    };

    const item = {
        hidden: { opacity: 0, y: 20 },
        show: {
            opacity: 1,
            y: 0,
            transition: { duration: 0.5, ease: "easeOut" }
        }
    };

    const filteredAlumni = alumni.filter(a =>
        a.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (a.company && a.company.toLowerCase().includes(searchTerm.toLowerCase())) ||
        (a.skills && a.skills.some(skill => skill.toLowerCase().includes(searchTerm.toLowerCase())))
    );

    if (loading) return <div className="p-8 text-center text-slate-500">Loading alumni directory...</div>;

    return (
        <PageTransition className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-900">Alumni Directory</h2>
                    <p className="text-slate-500">Find and connect with seniors from your domain</p>
                </div>

                <div className="flex gap-2">
                    <button className="flex items-center gap-2 px-4 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50">
                        <Filter size={18} /> Filters
                    </button>
                </div>
            </div>

            {/* Search Bar */}
            <div className="relative">
                <Search className="absolute left-4 top-3.5 text-slate-400" size={20} />
                <input
                    type="text"
                    placeholder="Search by name, company, or skills..."
                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 shadow-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            {/* Grid */}
            <motion.div
                className="grid md:grid-cols-2 lg:grid-cols-3 gap-6"
                variants={container}
                initial="hidden"
                animate="show"
            >
                {filteredAlumni.length > 0 ? (
                    filteredAlumni.map((alum) => (
                        <motion.div
                            key={alum._id}
                            variants={item}
                            whileHover={{ y: -4, boxShadow: "0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)" }}
                            className="bg-white p-6 rounded-2xl border border-slate-200 hover:border-blue-200 transition-colors group"
                        >
                            <div className="flex items-start justify-between mb-4">
                                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-lg">
                                    {alum.name[0]}
                                </div>
                                <div className="flex flex-col items-end gap-1">
                                    <span className="text-xs font-medium px-2 py-1 bg-slate-100 text-slate-600 rounded-md">
                                        {alum.batch || 'Alumni'}
                                    </span>
                                    {alum.badges && alum.badges.length > 0 && (
                                        <BadgeDisplay badge={alum.badges[alum.badges.length - 1]} size="xs" />
                                    )}
                                </div>
                            </div>

                            <h3 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-blue-600 transition-colors">
                                {alum.name}
                            </h3>
                            <div className="flex items-center gap-2 text-slate-600 mb-4 text-sm">
                                <Briefcase size={14} />
                                <span>{alum.jobTitle || 'Alumni'} at {alum.company || 'N/A'}</span>
                            </div>

                            <div className="flex items-center gap-2 text-slate-500 text-sm mb-4">
                                <MapPin size={14} />
                                <span>{alum.location || 'Remote'}</span>
                            </div>

                            <div className="flex flex-wrap gap-2 mb-6">
                                {alum.skills && alum.skills.length > 0 ? (
                                    alum.skills.map((skill, index) => (
                                        <span key={index} className="text-xs px-2 py-1 rounded-full bg-slate-50 text-slate-600 border border-slate-100">
                                            {skill}
                                        </span>
                                    ))
                                ) : (
                                    <span className="text-xs text-slate-400">No skills listed</span>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-3">
                                <Link
                                    to={`/student/create-query?type=targeted&targetAlumni=${alum._id}&name=${encodeURIComponent(alum.name)}`}
                                    className="flex items-center justify-center gap-2 py-2.5 rounded-xl bg-blue-50 text-blue-600 font-medium hover:bg-blue-100 transition-all"
                                >
                                    Message
                                </Link>
                                <Link
                                    to={`/student/alumni/${alum._id}`}
                                    className="flex items-center justify-center py-2.5 rounded-xl border border-blue-600 text-blue-600 font-medium hover:bg-blue-600 hover:text-white transition-all"
                                >
                                    Profile
                                </Link>
                            </div>
                        </motion.div>
                    ))
                ) : (
                    <div className="col-span-full text-center py-10 text-slate-500">
                        No alumni found matching your search.
                    </div>
                )}
            </motion.div>
        </PageTransition>
    );
};

export default ViewAlumni;

import { test, expect } from '@playwright/test';

test.describe('Alumni Features', () => {
    let userEmail;

    test.beforeEach(async ({ page }) => {
        // Generate unique email for each run
        userEmail = `alumni_visual_${Date.now()}@test.com`;
    });

    test('should register, use roadplan, and earn profile points', async ({ page }) => {
        test.setTimeout(60000);
        // 1. Register
        await page.goto('/register');
        await expect(page.getByText('Join the Community')).toBeVisible({ timeout: 10000 });

        await page.fill('input[name="name"]', 'Visual Tester');
        await page.fill('input[name="email"]', userEmail);
        await page.fill('input[name="password"]', 'password123');

        // Select Role: Click the Alumni card
        await page.getByText('I am an Alumni').click();

        // If there are other required fields, fill them. 
        // Assuming simple registration based on code review.

        await page.click('button[type="submit"]');

        // Wait for navigation or successful login
        // Usually redirects to '/login' or directly to dashboard
        // If redirects to login:
        if (page.url().includes('/login')) {
            await page.fill('input[type="email"]', userEmail);
            await page.fill('input[type="password"]', 'password123');
            // Select Role in Login (if consistent with Register/Login UI)
            // Using logic from Login.jsx: <button>alumni</button>
            await page.getByRole('button', { name: 'alumni' }).click();
            await page.click('button[type="submit"]');
        }

        // Should be at dashboard
        await expect(page).toHaveURL(/.*\/alumni\/dashboard/);
        await expect(page.getByText('Welcome back, Visual')).toBeVisible();

        // 2. Test Points Progress Widget
        // Check if widget is visible
        await expect(page.getByText('Your Progress')).toBeVisible();

        // Check for Progress Bar presence
        // Target the rounded full container
        const progressBarContainer = page.locator('.h-3.w-full.bg-slate-100');
        await expect(progressBarContainer).toBeVisible();

        // The gradient bar might start with width 0 due to animation. 
        // We check it exists in the DOM.
        const gradientBar = progressBarContainer.locator('div[class*="bg-gradient-to-r"]');
        await expect(gradientBar).toBeAttached();

        // 3. Test Profile Completion Points (and history modal)
        // 3. Test Profile Completion Points (and history modal)
        await page.click('div[class*="cursor-pointer"]'); // Click the widget to open modal
        await expect(page.getByText('Your Journey')).toBeVisible(); // Modal Title

        // Close modal by clicking outside (backdrop)
        // The backdrop covers the screen. Clicking top-left (0,0) should work.
        await page.mouse.click(10, 10);

        // Wait for modal to disappear
        await expect(page.getByText('Your Journey')).toBeHidden();

        // 3. Test Profile Completion Points
        await page.goto('/alumni/profile');

        // Click Edit Profile Button (Update selector based on AlumniProfile.jsx)
        await page.getByText('Edit Profile').click();

        // Fill Profile
        await page.fill('textarea[name="bio"]', 'Visual Test Bio');
        await page.fill('input[name="skills"]', 'Visual Testing, Automation'); // Text input

        await page.fill('input[name="company"]', 'Visual Corp');
        await page.fill('input[name="jobTitle"]', 'Visual Tester');
        await page.fill('input[name="location"]', 'Screen');
        await page.fill('input[name="linkedin"]', 'https://linkedin.com/in/visual');

        // Click Save Changes in Modal
        await page.click('button:has-text("Save Changes")');

        // Check Points on Dashboard
        await page.goto('/alumni/dashboard');

        // Find the card with "Community Points"
        const pointsCard = page.locator('.bg-white', { has: page.getByText('Community Points') });
        const pointsValue = await pointsCard.locator('.text-3xl').textContent();

        await expect(pointsCard.locator('.text-3xl')).toHaveText('50', { timeout: 10000 });
